gSs(){return"Feedback and support"},
gSr(){return"Send quick feedback directly from the app or open your email client."},
gSw(){return"Quick feedback"},
gSv(){return"Write your feedback here"},
gSx(){return"Send email"},
gSz(){return"Send feedback"},
gSt(){return"Enter feedback before sending."},
gSA(){return"Feedback sent. Thank you!"},
